// marshalTypesTriggerDefinitionToTriggerDefinitionResponseBody builds a value
// of type *TriggerDefinitionResponseBody from a value of type
// *types.TriggerDefinition.
func marshalTypesTriggerDefinitionToTriggerDefinitionResponseBody(v *types.TriggerDefinition) *TriggerDefinitionResponseBody {
	res := &TriggerDefinitionResponseBody{
		Slug:         v.Slug,
		Title:        v.Title,
		Description:  v.Description,
		Kind:         v.Kind,
		ConfigSchema: v.ConfigSchema,
	}
	if v.EnvRequirements != nil {
		res.EnvRequirements = make([]*TriggerEnvRequirementResponseBody, len(v.EnvRequirements))
		for i, val := range v.EnvRequirements {
			if val == nil {
				res.EnvRequirements[i] = nil
				continue
			}
			res.EnvRequirements[i] = marshalTypesTriggerEnvRequirementToTriggerEnvRequirementResponseBody(val)
		}
	} else {
		res.EnvRequirements = []*TriggerEnvRequirementResponseBody{}
	}

	return res
}

// marshalTypesTriggerEnvRequirementToTriggerEnvRequirementResponseBody builds
// a value of type *TriggerEnvRequirementResponseBody from a value of type
// *types.TriggerEnvRequirement.
func marshalTypesTriggerEnvRequirementToTriggerEnvRequirementResponseBody(v *types.TriggerEnvRequirement) *TriggerEnvRequirementResponseBody {
	res := &TriggerEnvRequirementResponseBody{
		Name:        v.Name,
		Description: v.Description,
		Required:    v.Required,
	}

	return res
}

// marshalTypesTriggerInstanceToTriggerInstanceResponseBody builds a value of
// type *TriggerInstanceResponseBody from a value of type
// *types.TriggerInstance.
func marshalTypesTriggerInstanceToTriggerInstanceResponseBody(v *types.TriggerInstance) *TriggerInstanceResponseBody {
	res := &TriggerInstanceResponseBody{
		ID:             v.ID,
		ProjectID:      v.ProjectID,
		DefinitionSlug: v.DefinitionSlug,
		Name:           v.Name,
		EnvironmentID:  v.EnvironmentID,
		TargetKind:     v.TargetKind,
		TargetRef:      v.TargetRef,
		TargetDisplay:  v.TargetDisplay,
		Status:         v.Status,
		WebhookURL:     v.WebhookURL,
		CreatedAt:      v.CreatedAt,
		UpdatedAt:      v.UpdatedAt,
	}
	if v.Config != nil {
		res.Config = make(map[string]any, len(v.Config))
		for key, val := range v.Config {
			tk := key
			tv := val
			res.Config[tk] = tv
		}
	}

	return res
}
